     1→import type { ProjectTrendDataPoint } from "@rudel/api-routes";
     2→import { Activity, Clock, TrendingUp, Zap } from "lucide-react";
     3→import { useMemo, useState } from "react";
     4→import {
     5→	Bar,
     6→	BarChart,
     7→	CartesianGrid,
     8→	Legend,
     9→	Line,
    10→	LineChart,
    11→	ResponsiveContainer,
    12→	Tooltip,
    13→	XAxis,
    14→	YAxis,
    15→} from "recharts";
    16→import { InfoTooltip } from "@/components/ui/InfoTooltip";
    17→import { useChartTheme } from "@/hooks/useChartTheme";
    18→import { ChartLegend } from "./ChartLegend";
    19→import { ChartTooltip } from "./ChartTooltip";
    20→
    21→const MAX_SERIES = 14;
    22→const OTHER_COLOR = "#9ca3af";
    23→
    24→interface ProjectTrendChartProps {
    25→	data: ProjectTrendDataPoint[];
    26→}
    27→
    28→type MetricType = "sessions" | "hours" | "tokens" | "success_rate";
    29→
    30→const METRICS = {
    31→	sessions: {
    32→		key: "sessions",
    33→		label: "Sessions",
    34→		icon: Activity,
    35→		formatter: (value: number) => value.toLocaleString(),
    36→	},
    37→	hours: {
    38→		key: "total_hours",
    39→		label: "Hours",
    40→		icon: Clock,
    41→		formatter: (value: number) => `${value.toFixed(1)}h`,
    42→	},
    43→	tokens: {
    44→		key: "total_tokens",
    45→		label: "Tokens",
    46→		icon: Zap,
    47→		formatter: (value: number) => {
    48→			if (value >= 1_000_000) return `${(value / 1_000_000).toFixed(1)}M`;
    49→			if (value >= 1_000) return `${(value / 1_000).toFixed(1)}K`;
    50→			return value.toFixed(0);
    51→		},
    52→	},
    53→	success_rate: {
    54→		key: "avg_success_rate",
    55→		label: "Success Rate",
    56→		icon: TrendingUp,
    57→		formatter: (value: number) => `${value.toFixed(0)}%`,
    58→		tooltip:
    59→			"Average session quality score (0–100): rewards git commits, high output ratio, and skill usage; deducts for errors and abandoned sessions.",
    60→	},
    61→};
    62→
    63→const PROJECT_COLORS = [
    64→	"#3b82f6",
    65→	"#10b981",
    66→	"#f59e0b",
    67→	"#8b5cf6",
    68→	"#ef4444",
    69→	"#ec4899",
    70→	"#14b8a6",
    71→	"#f97316",
    72→	"#6366f1",
    73→	"#84cc16",
    74→	"#06b6d4",
    75→	"#a855f7",
    76→	"#f43f5e",
    77→	"#0ea5e9",
    78→];
    79→
    80→export function ProjectTrendChart({ data }: ProjectTrendChartProps) {
    81→	const { gridStroke, axisStroke } = useChartTheme();
    82→	const [selectedMetric, setSelectedMetric] = useState<MetricType>("sessions");
    83→	const [hiddenSeries, setHiddenSeries] = useState<Set<string>>(new Set());
    84→	const toggleSeries = (key: string) =>
    85→		setHiddenSeries((prev) => {
    86→			const next = new Set(prev);
    87→			next.has(key) ? next.delete(key) : next.add(key);
    88→			return next;
    89→		});
    90→
    91→	const currentMetric = METRICS[selectedMetric];
    92→
    93→	// Rank projects by total sessions (stable ordering across metric changes)
    94→	const { topProjects, topProjectsSet, hasOther } = useMemo(() => {
    95→		const projectTotals = new Map<string, number>();
    96→		for (const d of data) {
    97→			projectTotals.set(
    98→				d.project_path,
    99→				(projectTotals.get(d.project_path) ?? 0) + d.sessions,
   100→			);
   101→		}
   102→		const sorted = Array.from(projectTotals.entries()).sort(
   103→			(a, b) => b[1] - a[1],
   104→		);
   105→		const top = sorted.slice(0, MAX_SERIES).map(([p]) => p);
   106→		return {
   107→			topProjects: top,
   108→			topProjectsSet: new Set(top),
   109→			hasOther: sorted.length > MAX_SERIES,
   110→		};
   111→	}, [data]);
   112→
   113→	const { chartData, seriesList } = useMemo(() => {
   114→		// Build full date range from all data
   115→		const existingDates = Array.from(new Set(data.map((d) => d.date))).sort();
   116→		const allDates: string[] = [];
   117→		if (existingDates.length > 0) {
   118→			const minDate = new Date(existingDates[0]);
   119→			const maxDate = new Date(existingDates[existingDates.length - 1]);
   120→			for (
   121→				let d = new Date(minDate);
   122→				d <= maxDate;
   123→				d.setDate(d.getDate() + 1)
   124→			) {
   125→				allDates.push(d.toISOString().split("T")[0]);
   126→			}
   127→		}
   128→
   129→		// "Other" only applies to summable metrics, not averages
   130→		const showOther = hasOther && selectedMetric !== "success_rate";
   131→		const seriesList = showOther ? [...topProjects, "Other"] : topProjects;
   132→
   133→		const chartData = allDates.map((date) => {
   134→			const dateObj: Record<string, string | number> = {
   135→				date,
   136→				displayDate: new Date(date).toLocaleDateString("en-US", {
   137→					month: "short",
   138→					day: "numeric",
   139→				}),
   140→			};
   141→
   142→			for (const projectPath of topProjects) {
   143→				const dp = data.find(
   144→					(d) => d.date === date && d.project_path === projectPath,
   145→				);
   146→				dateObj[projectPath] = dp
   147→					? (dp[currentMetric.key as keyof ProjectTrendDataPoint] as number)
   148→					: 0;
   149→			}
   150→
   151→			if (showOther) {
   152→				dateObj.Other = data
   153→					.filter((d) => d.date === date && !topProjectsSet.has(d.project_path))
   154→					.reduce(
   155→						(sum, d) =>
   156→							sum +
   157→							((d[
   158→								currentMetric.key as keyof ProjectTrendDataPoint
   159→							] as number) ?? 0),
   160→						0,
   161→					);
   162→			}
   163→
   164→			return dateObj;
   165→		});
   166→
   167→		return { chartData, seriesList };
   168→	}, [
   169→		data,
   170→		topProjects,
   171→		topProjectsSet,
   172→		hasOther,
   173→		selectedMetric,
   174→		currentMetric,
   175→	]);
   176→
   177→	const formatProjectName = (projectPath: string) => {
   178→		if (projectPath === "Other") return "Other";
   179→		const parts = projectPath.split("/");
   180→		return parts[parts.length - 1] || projectPath.substring(0, 20);
   181→	};
   182→
   183→	return (
   184→		<div className="space-y-4">
   185→			<div className="flex flex-wrap gap-2">
   186→				{Object.entries(METRICS).map(([key, metric]) => {
   187→					const isSelected = selectedMetric === key;
   188→					const Icon = metric.icon;
   189→					return (
   190→						<button
   191→							type="button"
   192→							key={key}
   193→							onClick={() => setSelectedMetric(key as MetricType)}
   194→							className={`
   195→								flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium
   196→								transition-all duration-200
   197→								${
   198→									isSelected
   199→										? "bg-accent-light text-accent-text border-2 border-accent"
   200→										: "bg-surface text-muted border-2 border-transparent hover:bg-hover"
   201→								}
   202→							`}
   203→						>
   204→							<Icon className="w-4 h-4" />
   205→							<span>{metric.label}</span>
   206→							{"tooltip" in metric && metric.tooltip && (
   207→								// biome-ignore lint/a11y/noStaticElementInteractions: tooltip stop-propagation wrapper
   208→								// biome-ignore lint/a11y/useKeyWithClickEvents: tooltip stop-propagation wrapper
   209→								<span onClick={(e) => e.stopPropagation()}>
   210→									<InfoTooltip text={metric.tooltip as string} />
   211→								</span>
   212→							)}
   213→						</button>
   214→					);
   215→				})}
   216→			</div>
   217→
   218→			<ResponsiveContainer width="100%" height={400}>
   219→				{selectedMetric === "success_rate" ? (
   220→					<LineChart
   221→						data={chartData}
   222→						margin={{ top: 10, right: 0, left: 0, bottom: 0 }}
   223→					>
   224→						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
   225→						<XAxis
   226→							dataKey="displayDate"
   227→							stroke={axisStroke}
   228→							style={{ fontSize: "12px" }}
   229→							angle={-45}
   230→							textAnchor="end"
   231→							height={80}
   232→							tickMargin={8}
   233→						/>
   234→						<YAxis
   235→							stroke={axisStroke}
   236→							style={{ fontSize: "12px" }}
   237→							tickFormatter={currentMetric.formatter}
   238→							domain={[0, 100]}
   239→						/>
   240→						<Tooltip
   241→							content={(props) => (
   242→								<ChartTooltip
   243→									{...props}
   244→									nameFormatter={formatProjectName}
   245→									valueFormatter={(v) => currentMetric.formatter(v)}
   246→									showTotal={false}
   247→								/>
   248→							)}
   249→						/>
   250→						<Legend
   251→							layout="vertical"
   252→							align="right"
   253→							verticalAlign="top"
   254→							width={160}
   255→							content={({ payload }) => (
   256→								<ChartLegend
   257→									payload={payload}
   258→									formatter={formatProjectName}
   259→									hiddenSeries={hiddenSeries}
   260→									onToggle={toggleSeries}
   261→								/>
   262→							)}
   263→						/>
   264→						{topProjects.map((projectPath, index) => (
   265→							<Line
   266→								key={projectPath}
   267→								type="monotone"
   268→								dataKey={projectPath}
   269→								stroke={PROJECT_COLORS[index % PROJECT_COLORS.length]}
   270→								strokeWidth={2}
   271→								dot={{ r: 3 }}
   272→								activeDot={{ r: 5 }}
   273→								connectNulls
   274→								hide={hiddenSeries.has(projectPath)}
   275→							/>
   276→						))}
   277→					</LineChart>
   278→				) : (
   279→					<BarChart
   280→						data={chartData}
   281→						margin={{ top: 10, right: 0, left: 0, bottom: 0 }}
   282→					>
   283→						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
   284→						<XAxis
   285→							dataKey="displayDate"
   286→							stroke={axisStroke}
   287→							style={{ fontSize: "12px" }}
   288→							angle={-45}
   289→							textAnchor="end"
   290→							height={80}
   291→							tickMargin={8}
   292→						/>
   293→						<YAxis
   294→							stroke={axisStroke}
   295→							style={{ fontSize: "12px" }}
   296→							tickFormatter={currentMetric.formatter}
   297→						/>
   298→						<Tooltip
   299→							content={(props) => (
   300→								<ChartTooltip
   301→									{...props}
   302→									nameFormatter={formatProjectName}
   303→									valueFormatter={(v) => currentMetric.formatter(v)}
   304→									showTotal
   305→								/>
   306→							)}
   307→						/>
   308→						<Legend
   309→							layout="vertical"
   310→							align="right"
   311→							verticalAlign="top"
   312→							width={160}
   313→							content={({ payload }) => (
   314→								<ChartLegend
   315→									payload={payload}
   316→									formatter={formatProjectName}
   317→									hiddenSeries={hiddenSeries}
   318→									onToggle={toggleSeries}
   319→								/>
   320→							)}
   321→						/>
   322→						{seriesList.map((projectPath, index) => (
   323→							<Bar
   324→								key={projectPath}
   325→								dataKey={projectPath}
   326→								stackId="1"
   327→								hide={hiddenSeries.has(projectPath)}
   328→								fill={
