   110→			return next;
   111→		});
   112→
   113→	const { chartData, dataKeys } = useMemo(() => {
   114→		if (!data || data.length === 0) {
   115→			return { chartData: [], dataKeys: [] };
   116→		}
   117→
   118→		let chartData: Record<string, unknown>[] = [];
   119→		let dataKeys: string[] = [];
   120→
   121→		if (split_by && data[0].split_values) {
   122→			const allSplitValues = new Set<string>();
   123→			for (const item of data) {
   124→				if (item.split_values) {
   125→					for (const key of Object.keys(item.split_values)) {
   126→						allSplitValues.add(key);
   127→					}
   128→				}
   129→			}
   130→			const rawSplitKeys = Array.from(allSplitValues);
   131→			// Map raw split keys to display names (e.g. user IDs → names)
   132→			const splitKeyDisplayMap: Record<string, string> = {};
   133→			for (const key of rawSplitKeys) {
   134→				splitKeyDisplayMap[key] = formatDimensionValue(key, split_by, userMap);
   135→			}
   136→			dataKeys = rawSplitKeys.map((key) => splitKeyDisplayMap[key]);
   137→
   138→			chartData = data.map((item) => {
   139→				const row: Record<string, unknown> = {
   140→					name: formatDimensionValue(item.dimension_value, dimension, userMap),
   141→					_fullName: item.dimension_value,
   142→					_total: 0,
   143→					_originalValues: {} as Record<string, number>,
   144→				};
   145→				const origValues = row._originalValues as Record<string, number>;
   146→				let total = 0;
   147→				for (const key of rawSplitKeys) {
   148→					const displayKey = splitKeyDisplayMap[key];
   149→					const val = item.split_values?.[key] || 0;
   150→					origValues[displayKey] = val;
   151→					total += val;
   152→				}
   153→				row._total = total;
   154→
   155→				if (showPercentage && total > 0) {
   156→					for (const key of rawSplitKeys) {
   157→						const displayKey = splitKeyDisplayMap[key];
   158→						row[displayKey] = (origValues[displayKey] / total) * 100;
   159→					}
   160→				} else {
   161→					for (const key of rawSplitKeys) {
   162→						const displayKey = splitKeyDisplayMap[key];
   163→						row[displayKey] = origValues[displayKey];
   164→					}
   165→				}
   166→
   167→				return row;
   168→			});
   169→
   170→			chartData.sort((a, b) => (b._total as number) - (a._total as number));
   171→		} else {
   172→			dataKeys = [formatMetricLabel(metric)];
   173→			chartData = data.map((item) => ({
   174→				name: formatDimensionValue(item.dimension_value, dimension, userMap),
   175→				_fullName: item.dimension_value,
   176→				[formatMetricLabel(metric)]: item.metric_value || 0,
   177→			}));
   178→
   179→			chartData.sort(
   180→				(a, b) =>
   181→					(b[formatMetricLabel(metric)] as number) -
   182→					(a[formatMetricLabel(metric)] as number),
   183→			);
   184→		}
   185→
   186→		return { chartData, dataKeys };
   187→	}, [data, dimension, metric, split_by, showPercentage, userMap]);
   188→
   189→	if (!data || data.length === 0) {
   190→		return (
   191→			<div className="flex items-center justify-center h-64 text-muted">
   192→				No data available for the selected dimension and metric
   193→			</div>
   194→		);
   195→	}
   196→
   197→	const renderTooltip = (props: Record<string, unknown>) => {
   198→		const { active, payload, label } = props;
   199→		if (!active || !Array.isArray(payload) || payload.length === 0) return null;
   200→
   201→		const payloadData = (payload[0] as Record<string, unknown>)?.payload as
   202→			| Record<string, unknown>
   203→			| undefined;
   204→		const fullName = (payloadData?._fullName || label) as string | undefined;
   205→		const originalValues = payloadData?._originalValues as
   206→			| Record<string, number>
   207→			| undefined;
   208→
   209→		// Build normalized items for ChartTooltip using raw values
   210→		const normalizedPayload = payload
   211→			.filter((entry: Record<string, unknown>) => {
   212→				const rawVal =
   213→					originalValues?.[entry.name as string] ?? (entry.value as number);
   214→				return rawVal !== 0;
   215→			})
   216→			.map((entry: Record<string, unknown>) => ({
   217→				name: entry.name as string,
   218→				value:
   219→					originalValues?.[entry.name as string] ?? (entry.value as number),
   220→				color: (entry.color ?? entry.fill) as string,
   221→			}));
   222→
   223→		const valueFormatter =
   224→			showPercentage && originalValues
   225→				? (v: number, name: string) => {
   226→						const pct = payload.find(
   227→							(e: Record<string, unknown>) => e.name === name,
   228→						);
   229→						const pctVal = pct ? (pct.value as number) : 0;
   230→						return `${formatNumberWithCommas(v)} (${pctVal.toFixed(1)}%)`;
   231→					}
   232→				: (v: number) => formatNumberWithCommas(v);
   233→
   234→		return (
   235→			<ChartTooltip
   236→				active={true}
   237→				payload={normalizedPayload}
   238→				label={fullName}
   239→				valueFormatter={valueFormatter}
   240→				showTotal={!showPercentage}
   241→			/>
   242→		);
   243→	};
   244→
   245→	return (
   246→		<div className="w-full">
   247→			<ResponsiveContainer width="100%" height={400}>
   248→				<BarChart
   249→					data={chartData}
   250→					layout="vertical"
   251→					margin={{ top: 20, right: 30, left: 10, bottom: 20 }}
   252→				>
   253→					<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
   254→					<XAxis
   255→						type="number"
   256→						className="text-xs"
   257→						tick={{ fill: axisStroke }}
   258→						tickFormatter={
   259→							showPercentage && split_by
   260→								? (value) => `${value.toFixed(0)}%`
   261→								: formatCompactNumber
   262→						}
   263→						domain={showPercentage && split_by ? [0, 100] : undefined}
   264→						label={{
   265→							value:
   266→								showPercentage && split_by
   267→									? "Percentage (%)"
   268→									: formatMetricLabel(metric),
   269→							position: "insideBottom",
   270→							offset: -10,
   271→							style: { textAnchor: "middle", fill: axisStroke },
   272→						}}
   273→					/>
   274→					<YAxis
   275→						type="category"
   276→						dataKey="name"
   277→						width={150}
   278→						className="text-xs"
   279→						tick={{ fill: axisStroke, fontSize: 12 }}
   280→						interval={0}
   281→					/>
   282→					<Tooltip
   283→						content={(props) => renderTooltip(props as Record<string, unknown>)}
   284→					/>
   285→					{split_by && (
   286→						<Legend
   287→							layout="vertical"
   288→							align="right"
   289→							verticalAlign="top"
   290→							width={160}
   291→							content={({ payload }) => (
   292→								<ChartLegend
   293→									payload={payload}
   294→									hiddenSeries={hiddenSeries}
   295→									onToggle={toggleSeries}
   296→								/>
   297→							)}
   298→						/>
   299→					)}
   300→					{split_by ? (
   301→						dataKeys.map((key, index) => (
   302→							<Bar
   303→								key={key}
   304→								dataKey={key}
   305→								stackId="stack"
   306→								hide={hiddenSeries.has(key)}
   307→								fill={CHART_COLORS[index % CHART_COLORS.length]}
   308→							/>
   309→						))
   310→					) : (
   311→						<Bar dataKey={formatMetricLabel(metric)} fill="#3b82f6" />
   312→					)}
   313→				</BarChart>
   314→			</ResponsiveContainer>
   315→		</div>
   316→	);
   317→});
